#define BLOCK_SIZE 16

const float amb_temp = 80.0f;

__kernel void hotspot(
    const int num_iterations,
    const __global float *power,
    const __global float *temp,
    __global float *result,
    const int row,
    const int col,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    int r = get_global_id(1);
    int c = get_global_id(0);

    if (r >= row || c >= col) return;

    float v_41 = step / Cap;
    float var_23 = 1.0f / Rx;
    float elem_44 = 1.0f / Ry;
    float var_32 = 1.0f / Rz;
    float elem_2 = step;

    for (int iter = 0; iter < num_iterations; iter++) {
        float delta;
        int idx = r * col + c;

        if (r == 0 && c == 0) {
            delta = v_41 * (power[idx] +
                (temp[idx + 1] - temp[idx]) * var_23 +
                (temp[idx + col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (r == 0 && c == col - 1) {
            delta = v_41 * (power[idx] +
                (temp[idx - 1] - temp[idx]) * var_23 +
                (temp[idx + col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (r == row - 1 && c == col - 1) {
            delta = v_41 * (power[idx] +
                (temp[idx - 1] - temp[idx]) * var_23 +
                (temp[idx - col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (r == row - 1 && c == 0) {
            delta = v_41 * (power[idx] +
                (temp[idx + 1] - temp[idx]) * var_23 +
                (temp[idx - col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (r == 0) {
            delta = v_41 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                (temp[idx + col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (c == col - 1) {
            delta = v_41 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                (temp[idx - 1] - temp[idx]) * var_23 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (r == row - 1) {
            delta = v_41 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                (temp[idx - col] - temp[idx]) * elem_44 +
                (amb_temp - temp[idx]) * var_32);
        }
        else if (c == 0) {
            delta = v_41 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                (temp[idx + 1] - temp[idx]) * var_23 +
                (amb_temp - temp[idx]) * var_32);
        }
        else {
            delta = v_41 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                (amb_temp - temp[idx]) * var_32);
        }

        result[idx] = temp[idx] + delta;
    }
}
